import re
import numpy as np
from sklearn import linear_model, datasets
from sklearn.feature_extraction.text import CountVectorizer

def get_spam(email):
    # Load the spam dataset
    emails = datasets.load_files('emails', encoding='utf-8')

    # Use a regular expression to replace email addresses with 'emailaddr'
    processed_emails = []
    for email in emails.data:
        processed_emails.append(re.sub('\S*@\S*\s?', 'emailaddr', email))

    # Get the features from the emails
    vectorizer = CountVectorizer()
    X = vectorizer.fit_transform(processed_emails)

    # Train a logistic regression classifier
    clf = linear_model.LogisticRegressionCV()
    clf.fit(X, emails.target)

    # Return spam probability
    return clf.predict_proba([vectorizer.transform([email])])[0][1]

